package com.example.rentscope.data.local

import android.util.Base64
import com.squareup.moshi.Json
import org.json.JSONObject

internal data class OfflineMunicipalitySeedDto(
    @Json(name = "codigo_municipio")
    val codigoMunicipio: Int,

    @Json(name = "municipio_localidade")
    val municipioLocalidade: String,

    val regiao: String?,

    @Json(name = "grande_regiao")
    val grandeRegiao: String?,

    @Json(name = "renda_trimestre")
    val rendaTrimestre: String?,

    @Json(name = "valor_medio_m2")
    val valorMedioM2: Float?,

    @Json(name = "total_escolas")
    val totalEscolas: Int,

    @Json(name = "total_hospitais")
    val totalHospitais: Int,

    @Json(name = "total_crimes")
    val totalCrimes: Int
)

internal object OfflineMunicipalityBaseline {
    private val cachedSeed by lazy {
        val encodedJson = ENCODED_JSON_CHUNKS.joinToString(separator = "")
        val json = String(Base64.decode(encodedJson, Base64.DEFAULT), Charsets.UTF_8)
        parseSeed(json).map(::fixSeedEncoding)
    }

    fun load(): List<OfflineMunicipalitySeedDto> {
        return cachedSeed
    }

    private fun parseSeed(json: String): List<OfflineMunicipalitySeedDto> {
        val root = JSONObject(json)
        val items = root.optJSONArray("value") ?: return emptyList()

        return buildList(items.length()) {
            for (index in 0 until items.length()) {
                val item = items.optJSONObject(index) ?: continue

                add(
                    OfflineMunicipalitySeedDto(
                        codigoMunicipio = item.optInt("codigo_municipio"),
                        municipioLocalidade = item.optString("municipio_localidade"),
                        regiao = item.readNullableString("regiao"),
                        grandeRegiao = item.readNullableString("grande_regiao"),
                        rendaTrimestre = item.readNullableString("renda_trimestre"),
                        valorMedioM2 = item.readNullableFloat("valor_medio_m2"),
                        totalEscolas = item.optInt("total_escolas"),
                        totalHospitais = item.optInt("total_hospitais"),
                        totalCrimes = item.optInt("total_crimes")
                    )
                )
            }
        }
    }

    private fun fixSeedEncoding(item: OfflineMunicipalitySeedDto): OfflineMunicipalitySeedDto {
        return item.copy(
            municipioLocalidade = fixEncoding(item.municipioLocalidade).orEmpty(),
            regiao = fixEncoding(item.regiao),
            grandeRegiao = fixEncoding(item.grandeRegiao),
            rendaTrimestre = fixEncoding(item.rendaTrimestre)
        )
    }

    private fun fixEncoding(value: String?): String? {
        val text = value?.trim()
        if (text.isNullOrEmpty()) {
            return text
        }

        if (!text.contains("Ã") && !text.contains("Â") && !text.contains("¢") && !text.contains("º")) {
            return text
        }

        return try {
            String(text.toByteArray(Charsets.ISO_8859_1), Charsets.UTF_8)
        } catch (_: Exception) {
            text
        }
    }

    private fun JSONObject.readNullableString(key: String): String? {
        if (isNull(key)) {
            return null
        }

        return optString(key).takeUnless { it.equals("null", ignoreCase = true) }
    }

    private fun JSONObject.readNullableFloat(key: String): Float? {
        if (isNull(key)) {
            return null
        }

        return optDouble(key)
            .takeIf { it.isFinite() }
            ?.toFloat()
    }

    private val ENCODED_JSON_CHUNKS = listOf(
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        ""
    )
}

